from typing import List

class Solution:
    def subsets(self, nums: List[int]) -> List[List[int]]:
        n = len(nums)
        result = []
        for mask in range(1 << n):
            subset = [nums[j] for j in range(n) if mask & (1 << j)]
            result.append(subset)
        return result
